import { Platform } from 'react-native';

const API_URL = 'https://api.example.com';
const API_KEY = 'your_api_key_here'; // replace with your actual API key

// Helper function to handle API requests
async function apiRequest(method, endpoint, data = null) {
  try {
    const response = await fetch(`${API_URL}${endpoint}`, {
      method,
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': API_KEY,
      },
      body: JSON.stringify(data),
    });

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    const json = await response.json();
    return json;
  } catch (error) {
    console.error('API request failed:', error);
    throw error;
  }
}

// Authentication function
async function authenticate(username, password) {
  try {
    const response = await apiRequest('POST', '/auth/login', { username, password });
    return response.token;
  } catch (error) {
    console.error('Authentication failed:', error);
    throw error;
  }
}

// User profile fetching function
async function getUserProfile(token) {
  try {
    const response = await apiRequest('GET', '/users/me', null, { headers: { Authorization: `Bearer ${token}` } });
    return response.data;
  } catch (error) {
    console.error('Failed to fetch user profile:', error);
    throw error;
  }
}

// Data update function
async function updateData(token, data) {
  try {
    const response = await apiRequest('PUT', '/data/update', data, { headers: { Authorization: `Bearer ${token}` } });
    return response.data;
  } catch (error) {
    console.error('Failed to update data:', error);
    throw error;
  }
}

